import { attachChannelToResult } from "openclaw/plugin-sdk/channel-send-result";
import {
  createChatChannelPlugin,
  getChatChannelMeta,
  type OpenClawConfig,
} from "openclaw/plugin-sdk/core";
import type { PulseBoardAccount } from "./types.js";

const DEFAULT_ACCOUNT_ID = "default";

interface ResolvedPulseBoardAccount extends PulseBoardAccount {
  accountId: string;
  enabled: boolean;
  configured: boolean;
}

function listPulseBoardAccountIds(cfg: OpenClawConfig): string[] {
  const channels = cfg.channels as Record<string, unknown> | undefined;
  const pbCfg = channels?.pulseboard as Record<string, unknown> | undefined;
  const accounts = pbCfg?.accounts as Record<string, unknown> | undefined;
  const ids = accounts ? Object.keys(accounts) : [];
  return ids.length > 0 ? ids : [DEFAULT_ACCOUNT_ID];
}

function resolvePulseBoardAccount(
  cfg: OpenClawConfig,
  accountId?: string | null,
): ResolvedPulseBoardAccount {
  const aid = accountId?.trim() || DEFAULT_ACCOUNT_ID;
  const channels = cfg.channels as Record<string, unknown> | undefined;
  const pbCfg = channels?.pulseboard as Record<string, unknown> | undefined;
  const accounts = pbCfg?.accounts as Record<string, unknown> | undefined;
  const account = accounts?.[aid] as Partial<PulseBoardAccount> | undefined;

  const boardUrl = account?.boardUrl?.trim() ?? "";
  const apiToken = account?.apiToken?.trim() ?? "";
  const username = account?.username?.trim() ?? "";

  return {
    accountId: aid,
    enabled: true,
    configured: Boolean(boardUrl && apiToken && username),
    boardUrl,
    apiToken,
    username,
  };
}

